// hello.cpp - Simple C++ program
#include <iostream>

int main() {
    std::cout << "Hello, World!" << std::endl;
    return 0;
}

// Compilation command in terminal:
// g++ hello.cpp -o hello
// 
// Execution:
// ./hello
// Output: Hello, World!

// mathutils.h
#ifndef MATHUTILS_H
#define MATHUTILS_H

int add(int a, int b);
int multiply(int a, int b);

#endif

// mathutils.cpp
#include "mathutils.h"

int add(int a, int b) {
    return a + b;
}

int multiply(int a, int b) {
    return a * b;
}

// main.cpp
#include <iostream>
#include "mathutils.h"

int main() {
    std::cout << "Add: " << add(5, 3) << std::endl;
    std::cout << "Multiply: " << multiply(4, 7) << std::endl;
    return 0;
}

// Compilation commands:
// g++ main.cpp mathutils.cpp -o calculator
// OR with headers:
// g++ main.cpp mathutils.cpp -I. -o calculator
// 
// Execution:
// ./calculator

// demo.cpp
#include <iostream>
#define NUMBER 42

int main() {
    std::cout << "Value: " << NUMBER << std::endl;
    return 0;
}

// Stage 1: Preprocessing
// g++ -E demo.cpp -o demo.i
// Output: Expanded source with macros replaced

// Stage 2: Compilation to assembly
// g++ -S demo.cpp -o demo.s
// Output: Assembly language code

// Stage 3: Assembly to object code
// g++ -c demo.cpp -o demo.o
// Output: Binary object file

// Stage 4: Linking
// g++ demo.o -o demo
// Output: Final executable

// Combined with optimization:
// g++ -O2 -Wall -std=c++17 demo.cpp -o demo
// -O2: Optimization level 2
// -Wall: Enable all warnings
// -std=c++17: Use C++17 standard
